export const pinnedSymbols: string[] = [
  "BTC", "ETH", "SOL", "XRP", "USDT", "USDC", "BNB", "DOGE", "TRX", "ADA", "LTC", "AVAX", "LINK", "DOT", "POL", "BCH", "XLM", "TON", "SHIB", "UNI"
];

const bySymbol = new Map(cryptoAssets.map((a) => [a.symbol, a]));
export const getAsset = (symbol: string) => bySymbol.get(symbol);

export const pinnedAssets: CryptoAsset[] = pinnedSymbols
  .map((s) => bySymbol.get(s))
  .filter((a): a is CryptoAsset => Boolean(a));

// Pinned assets first (in defined order), then the rest by rank.
export const orderedAssets: CryptoAsset[] = [
  ...pinnedAssets,
  ...cryptoAssets.filter((a) => !pinnedSymbols.includes(a.symbol)),
];

export const popularAssets = orderedAssets.filter((a) => a.isPopular);
export const stablecoins = orderedAssets.filter((a) => a.isStablecoin);

export const formatUsd = (n: number) =>
  n >= 1
    ? n.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })
    : n.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 8 });

export const formatTokenAmount = (n: number) =>
  n.toLocaleString("en-US", { maximumFractionDigits: n >= 1 ? 6 : 2 });
